effect.shader:
void main() {
    int from = -max(1,int(radius));
    int to = max(1,int(radius));
    // Size of a pixel
    vec2 imgSize = getTexSize(inputImg.size);
    float px = (1.0/imgSize.x);
    float py = (1.0/imgSize.y);
    if( acPass==0 ) {
        float nearestOutside = radius * 2.0;
        for(int i=from; i<to; i++ ) {
            vec4 inColor = texture2DCv(inputImg.texture,vec2(acScreenNorm.s + float(i)*px + sdx*px,acScreenNorm.t));
            float xdistOut = inColor.a > 0.0 ? abs(float(i)) : radius*2.0;
            nearestOutside = min(nearestOutside,xdistOut);
        }
        gl_FragColor = vec4(nearestOutside/radius, 0.0, 0.0, 1.0);
    } else {
        float tOut = 2.0;
        for(int i=from; i<to; i++ ) {
            vec4 inColor = texture2DCv(hdist.texture,vec2(acScreenNorm.s,acScreenNorm.t + float(i)*py + sdy*py));
            float xdistOut = inColor.r;
            float ydist = abs(float(i))/radius;
            float distOut = length(vec2(xdistOut,ydist));
            tOut = min(tOut,distOut);
        }
        vec4 original = texture2DCv(inputImg.texture,acScreenNorm.st);
        vec4 outColor = mix(vec4(0.0,0.0,0.0,0.5), vec4(0.0), smoothstep(0.0,1.0,tOut));
        vec4 result = outColor;
        result = original + result*(1.0-original.a);
        gl_FragColor = result;
    }
}
